#include <queue>
#include <utility>
#include <climits>

using namespace std;

long long solve(vector<vector<long long>> grid, long long k) {
    int m = grid.size();
    int n = grid[0].size();
    priority_queue<tuple<long long, int, int, long long>, vector<tuple<long long, int, int, long long>>, greater<>> pq;
    vector<vector<vector<long long>>> dist(m, vector<vector<long long>>(n, vector<long long>(k + 1, INT_MAX)));
    dist[0][0][0] = 0;
    pq.push(make_tuple(0, 0, 0, 0));

    while (!pq.empty()) {
        auto [cost, i, j, cnt] = pq.top();
        pq.pop();

        if (i == m - 1 && j == n - 1) {
            return cost;
        }

        if (cnt >= k) {
            continue;
        }

        // Regular move: right
        if (j + 1 < n) {
            long long new_cost = cost + grid[i][j + 1];
            if (new_cost < dist[i][j + 1][cnt]) {
                dist[i][j + 1][cnt] = new_cost;
                pq.push(make_tuple(new_cost, i, j + 1, cnt));
            }
        }

        // Regular move: down
        if (i + 1 < m) {
            long long new_cost = cost + grid[i + 1][j];
            if (new_cost < dist[i + 1][j][cnt]) {
                dist[i + 1][j][cnt] = new_cost;
                pq.push(make_tuple(new_cost, i + 1, j, cnt));
            }
        }

        // Teleport
        for (int x = 0; x < m; ++x) {
            for (int y = 0; y < n; ++y) {
                if (grid[x][y] <= grid[i][j] && x != i || y != j) {
                    if (cost < dist[x][y][cnt + 1]) {
                        dist[x][y][cnt + 1] = cost;
                        pq.push(make_tuple(cost, x, y, cnt + 1));
                    }
                }
            }
        }
    }

    return -1;
}
